sql:
SELECT metric_id, rms, rms_avg, entropy
FROM signal_metrics
WHERE rms > rms_avg;

external_knowledge:
- 'most frequently accessed signals' refers to the signals with the highest access counts; 
- 'total access counts' is the sum of all access counts for each signal; 
- 'ranked... in descending order' means that the signals with higher access counts are ranked higher; 
- 'alphabetically by signal name' means arranging the signals in order from A to Z based on their names.

sql:
SELECT signal_id, rms_avg, entropy, analysis_status
FROM signal_metrics
ORDER BY rms_avg DESC;

SELECT signal_id, rms_max, signal_quality
FROM signal_metrics
ORDER BY rms_max DESC;
